<template><main class="phone-page"><header class="mobile-header"><span></span><h1>个人中心</h1><span></span></header><div class="mobile-content"><section class="panel profile"><div class="avatar">{{ initial }}</div><h2>{{ user.realName || '公众监督员' }}</h2><p>{{ user.telId }}</p></section><section class="panel"><div class="row"><span>账号类型</span><b>公众监督员</b></div><div class="row"><span>出生日期</span><b>{{ user.birthday || '-' }}</b></div><div class="row"><span>性别</span><b>{{ user.sex===0?'女':'男' }}</b></div><button class="secondary-btn" @click="logout">退出登录</button></section></div><BottomNav /></main></template>
<script setup>import { computed } from 'vue';import { useRouter } from 'vue-router';import BottomNav from '../components/BottomNav.vue';import { getSessionStorage,removeSessionStorage } from '../common.js';const router=useRouter();const user=getSessionStorage('supervisor')||{};const initial=computed(()=>(user.realName||'监').slice(0,1));const logout=()=>{removeSessionStorage('supervisor');router.push('/login')}</script>
<style scoped>.profile{text-align:center}.avatar{width:68px;height:68px;margin:auto;border-radius:50%;display:grid;place-items:center;background:#e2f5ed;color:#17a674;font-size:28px;font-weight:700}.profile h2{margin:12px 0 4px}.profile p{margin:0;color:#718095}.row{display:flex;justify-content:space-between;padding:14px 0;border-bottom:1px solid #e4ebf2}.row span{color:#718095}</style>
